impl Solution { pub fn min_operations(s1: String, s2: String, x: i32) -> i32 { let black_d: Vec<_> = s1.bytes().zip(s2.bytes()).enumerate().filter(|(_, (a, b))| a != b).map(|(i, _)| i as i64).collect(); if black_d.len() % 2 != 0 { return -1; } if black_d.is_empty() { return 0; } let (n, mut black_dp) = (black_d.len(), vec![0i64; 501]); black_dp[0] = x as i64; for i in 1..n { black_dp[i] = (black_dp[i-1] + x as i64).min(if i >= 1 { (if i >= 2 { black_dp[i-2] } else { 0 }) + (black_d[i] - black_d[i-1]) * 2 } else { i64::MAX }); } (black_dp[n-1] / 2) as i32 } }